// ═══════════════════════════════════════════════════════════════
//  ENTITY
// ═══════════════════════════════════════════════════════════════
class Entity {
  constructor(image, x, y, w, h, step = 2.3, radiusView = 8) {
    this.entityImg = new Image();
    this.entityImg.src = image;
    this.x = x; this.y = y; this.w = w; this.h = h;
    this.g = 0; this.jumping = false; this.step = step;
    this.dir = 1; this.stop = true;
    this.name = "ent" + Entity.count;
    this.goTo = -1; this.radiusView = radiusView;
    this.collecting = false; this.died = false;
    this.diedTimer = 0;   // для анимации смерти
    Entity.count += 1;
  }
  draw(ctx, backZonePlayer) {
    ctx.beginPath();
    if (!this.died) {
      if (this.stop)
        ctx.drawImage(this.entityImg, 0, 100*(this.dir==1?0:1), 80, 100,
          this.x-this.w/2-backZonePlayer, this.y-this.h, 51, 64);
      else {
        let cadr = Math.floor(this.x/20);
        ctx.drawImage(this.entityImg, 80*(cadr%4), 100*(this.dir==1?0:1), 80, 100,
          this.x-this.w/2-backZonePlayer, this.y-this.h, 51, 64);
      }
    } else {
      // анимация смерти — бот лежит, постепенно исчезает
      ctx.save();
      ctx.globalAlpha = Math.max(0, 1 - this.diedTimer/3000);
      ctx.drawImage(this.entityImg, 0, 200, 80, 100,
        this.x-this.w/2-backZonePlayer, this.y-this.h, 51, 64);
      ctx.restore();
    }
    ctx.stroke();
  }
  gravity(relief, ms) {
    let h = relief[Math.floor(this.x/64)];
    if (this.y != h) {
      this.jumping = true;
      this.g += Math.floor(1*ms/25);
      let dy = Math.floor(this.g*ms/25);
      if (this.y < h) this.y += dy;
      if (this.y > h) { this.y = h; this.g = 0; }
    } else { this.jumping = false; }
  }
  jump() { this.y--; this.g = -11; this.jumping = true; }
}
Entity.count = -1;

// ═══════════════════════════════════════════════════════════════
//  PLAYER
// ═══════════════════════════════════════════════════════════════
class Player extends Entity {
  setVars(point) {
    this.point = point; this.load = 0;
    this.backZone = 0; this.food = 10;
    delete this.goTo; delete this.radiusView;
  }
  draw(ctx) {
    ctx.beginPath();
    if (this.stop)
      ctx.drawImage(this.entityImg, 0, 100*(this.dir==1?0:1), 80, 100,
        this.x-this.w/2, this.y-this.h, 51, 64);
    else {
      let cadr = Math.floor((this.x+this.backZone)/20);
      ctx.drawImage(this.entityImg, 80*(cadr%4), 100*(this.dir==1?0:1), 80, 100,
        this.x-this.w/2, this.y-this.h, 51, 64);
    }
    ctx.stroke();
    if (this.load != 0) this.drawColl(ctx);
  }
  woodCollection() { this.point += Math.round(Math.random()*9+1); }
  drawColl(ctx) {
    let state = this.load;
    ctx.fillStyle = 'white';
    ctx.fillRect(this.x-16, this.y-74, 2*state, 2);
    state = 16-state;
    if (state != 0) { ctx.fillStyle='gray'; ctx.fillRect(this.x+16, this.y-74, -2*state, 2); }
  }
  moving(relief, ms) {
    let dx = this.dir * Math.floor(this.step*(ms/25));
    if (relief[Math.floor(((this.x+this.backZone)+this.dir*(this.step+6))/64)] >= this.y)
      this.x += dx;
    if (this.x < 0) this.x = 0;
    if (this.x > 320) { this.backZone += this.x-320; this.x = 320; }
  }
  gravity(relief, ms) {
    let h = relief[Math.floor((this.x+this.backZone)/64)];
    if (this.y != h) {
      this.jumping = true;
      this.g += Math.floor(1*ms/25);
      let dy = Math.floor(this.g*ms/25);
      if (this.y < h) this.y += dy;
      if (this.y > h) { this.y = h; this.g = 0; }
    } else { this.jumping = false; }
  }
}

// ═══════════════════════════════════════════════════════════════
//  RIVAL
// ═══════════════════════════════════════════════════════════════
class Rival extends Entity {
  AI(obj, relief, dwood, ms) {
    // анимация смерти — ждём пока исчезнет
    if (this.died) { this.diedTimer += ms; return; }
    if (this.goTo == -1) {
      if (!this.died) this.searchDwood(dwood);
      if (this.goTo == -1 && !this.died) this.dying(obj);
    } else {
      if (Math.abs(this.x-this.goTo) > 3) { this.stop=false; this.moving(relief,ms); }
      else if (!this.collecting && dwood.isWood(this.x)) { this.stop=true; this.collecting=true; this.woodCollection(obj,dwood); }
      else this.goTo = -1;
    }
  }
  searchDwood(dwood) {
    if (dwood.isWood(this.x)) this.goTo = this.x;
    else {
      for (let i=1; i<=this.radiusView; i++) {
        let l=-32*i+this.x, r=32*i+this.x;
        if (dwood.isWood(r)) { this.goTo=r; break; }
        if (dwood.isWood(l)) { this.goTo=l; break; }
      }
    }
    if (this.goTo<8||this.goTo>6394) this.goTo=-1;
    if (this.goTo!=-1) this.dir = this.x<this.goTo?1:-1;
  }
  woodCollection(obj, dwood) {
    setTimeout(function(obj,dwood){ dwood.collection(obj.x); obj.collecting=false; obj.goTo=-1; }, 1000, obj, dwood);
  }
  moving(relief, ms) {
    let dx = this.dir*Math.floor(this.step*(ms/25));
    if (relief[Math.floor((this.x+this.dir*(this.step+6))/64)] >= this.y) this.x += dx;
    else if (!this.jumping) this.jump();
    if (this.x<0) this.x=0;
  }
  dying(obj) { this.died=true; this.diedTimer=0; }
}

// ═══════════════════════════════════════════════════════════════
//  RESOURCES
// ═══════════════════════════════════════════════════════════════
class Resources {
  constructor(relief) {
    this.resImg = new Image(); this.resImg.src = '../img/dwood.png';
    this.berryImg = new Image(); this.berryImg.src = '../img/dwood.png'; // fallback
    this.location = []; this.types = [];  // 0=empty 1=wood 2=berries
    let length = relief.length*2;
    for (var i=0; i<length; i++) {
      let roll = Math.random();
      if (roll > 0.5) {
        this.location[i] = relief[Math.floor(i/2)]-8;
        this.types[i] = Math.random() > 0.85 ? 2 : 1;  // 15% ягоды
      } else {
        this.location[i] = 0; this.types[i] = 0;
      }
    }
  }
  draw(ctx, backZone) {
    let l=Math.floor(backZone/32), r=Math.min(l+21,this.location.length);
    for (var i=l; i<r; i++) {
      if (this.location[i]!=0) {
        ctx.beginPath();
        if (this.types[i]===2) {
          // ягоды — красный кружок
          ctx.fillStyle='rgba(180,40,40,0.9)';
          ctx.arc(i*32-backZone+12, this.location[i]+10, 5, 0, Math.PI*2);
          ctx.fill();
          ctx.fillStyle='rgba(220,60,60,0.7)';
          ctx.beginPath();
          ctx.arc(i*32-backZone+20, this.location[i]+7, 4, 0, Math.PI*2);
          ctx.fill();
          ctx.fillStyle='rgba(100,160,50,0.8)';
          ctx.fillRect(i*32-backZone+10, this.location[i]+2, 2, 6);
        } else {
          ctx.drawImage(this.resImg, i*32-backZone, this.location[i]);
        }
        ctx.stroke();
      }
    }
  }
  collection(x) { this.location[Math.floor(x/32)]=0; this.types[Math.floor(x/32)]=0; }
  isWood(x) { let a=Math.floor(x/32); if(a<0||a>this.location.length) return false; return this.location[a]!=0; }
  isBerry(x) { let a=Math.floor(x/32); if(a<0||a>this.location.length) return false; return this.types[a]===2; }
}

// ═══════════════════════════════════════════════════════════════
//  BACKGROUND
// ═══════════════════════════════════════════════════════════════
class Background {
  constructor() {
    this.woodImg=new Image(); this.woodImg.src='../img/front.png';
    this.back=new Image(); this.back.src='../img/back.png';
    this.position=0;
  }
  draw(ctx, player) {
    ctx.beginPath(); ctx.fillStyle='#0a0a0a'; ctx.fillRect(0,0,640,400);
    if (this.position==0 && player.x+player.backZone<320) {
      ctx.drawImage(this.back,0,0,640,400); ctx.drawImage(this.woodImg,0,0,640,400);
    } else {
      let x=player.x+player.backZone;
      if (player.x==320) {
        this.position=x;
        ctx.drawImage(this.back,(80-x/4+640*Math.floor((x-320)/2560)),0,640,400);
        ctx.drawImage(this.back,(720-x/4+640*Math.floor((x-320)/2560)),0,640,400);
        ctx.drawImage(this.woodImg,(160-x/2+640*Math.floor((x-320)/1280)),0,640,400);
        ctx.drawImage(this.woodImg,(800-x/2+640*Math.floor((x-320)/1280)),0,640,400);
      } else {
        ctx.drawImage(this.back,(80-this.position/4+640*Math.floor((this.position-320)/2560)),0,640,400);
        ctx.drawImage(this.back,(720-this.position/4+640*Math.floor((this.position-320)/2560)),0,640,400);
        ctx.drawImage(this.woodImg,(160-this.position/2+640*Math.floor((this.position-320)/1280)),0,640,400);
        ctx.drawImage(this.woodImg,(800-this.position/2+640*Math.floor((this.position-320)/1280)),0,640,400);
      }
    }
    ctx.stroke();
  }
}

// ═══════════════════════════════════════════════════════════════
//  GROUND
// ═══════════════════════════════════════════════════════════════
class Ground {
  constructor(image, length) {
    this.relief=[]; this.grassImg=new Image(); this.grassImg.src=image;
    for (var i=0; i<length; i++)
      this.relief[i]=400-(Math.floor(Math.random()*(3-1))+1)*32;
    [50,51,52,93,94,95,96].forEach(i=>this.relief[i]=336);
  }
  draw(ctx, backZone) {
    let l=Math.floor(backZone/64), r=Math.min(l+11,this.relief.length);
    for (var i=l; i<r; i++) { ctx.beginPath(); ctx.drawImage(this.grassImg,i*64-backZone,this.relief[i]); ctx.stroke(); }
  }
}

// ═══════════════════════════════════════════════════════════════
//  SHOP
// ═══════════════════════════════════════════════════════════════
class Shop {
  constructor(image, x) {
    this.img=new Image(); this.img.src=image; this.x=x; this.y=144;
    this.glowPhase=Math.random()*Math.PI*2;
  }
  draw(ctx, backZone, playerWorldX, playerWood, glbuy) {
    ctx.beginPath(); ctx.drawImage(this.img,this.x-backZone,this.y); ctx.stroke();
    let dist=Math.abs(playerWorldX-this.x);
    if (dist < 200) {
      this.glowPhase+=0.08;
      let intensity=(Math.sin(this.glowPhase)*0.5+0.5)*(1-dist/200)*0.5;
      let gx=this.x-backZone+64, gy=this.y+60;
      let g=ctx.createRadialGradient(gx,gy,0,gx,gy,80);
      g.addColorStop(0,`rgba(255,200,50,${intensity})`); g.addColorStop(1,'rgba(0,0,0,0)');
      ctx.fillStyle=g; ctx.fillRect(gx-80,gy-80,160,160);
      // подсказка — сколько еды получишь
      if (dist < 120 && playerWood > 0 && glbuy > 0) {
        let foodGain = Math.floor(playerWood/glbuy);
        if (foodGain > 0) {
          ctx.font='bold 11px "Courier New",monospace';
          ctx.fillStyle='rgba(255,220,80,0.85)';
          let hint=`+${foodGain} 🍖`;
          ctx.fillText(hint, this.x-backZone+64-ctx.measureText(hint).width/2, this.y-8);
        }
      }
    }
  }
}

// ═══════════════════════════════════════════════════════════════
//  INTERFACE — HUD
// ═══════════════════════════════════════════════════════════════
class Interface {
  constructor() {}
  draw(ctx, x, food, wood, buy, ms, runNum) {
    let W = ctx.canvas.width;
    ctx.fillStyle='rgba(0,0,0,0.75)'; ctx.fillRect(0,0,W,48);
    ctx.fillStyle='rgba(255,255,255,0.06)'; ctx.fillRect(0,47,W,1);

    ctx.font='bold 13px "Courier New",monospace';
    let foodColor=food>5?'#7ecb7e':food>2?'#f0c060':'#e05555';
    ctx.fillStyle='rgba(255,255,255,0.25)'; ctx.fillText('FOOD',18,20);
    ctx.font='bold 18px "Courier New",monospace'; ctx.fillStyle=foodColor; ctx.fillText(food,18,40);

    ctx.font='bold 13px "Courier New",monospace'; ctx.fillStyle='rgba(255,255,255,0.25)';
    let wl='WOOD'; ctx.fillText(wl,W/2-Math.floor(ctx.measureText(wl).width/2),20);
    ctx.font='bold 18px "Courier New",monospace'; ctx.fillStyle='#c8a96e';
    let wt=String(wood); ctx.fillText(wt,W/2-Math.floor(ctx.measureText(wt).width/2),40);

    ctx.font='bold 13px "Courier New",monospace'; ctx.fillStyle='rgba(255,255,255,0.25)';
    let cl='COST'; ctx.fillText(cl,W-18-ctx.measureText(cl).width,20);
    ctx.font='bold 18px "Courier New",monospace'; ctx.fillStyle='#a0a0cc';
    let ct=String(buy); ctx.fillText(ct,W-18-ctx.measureText(ct).width,40);

    ctx.fillStyle='rgba(255,255,255,0.08)';
    ctx.fillRect(W/3,8,1,32); ctx.fillRect(W*2/3,8,1,32);

    if(runNum>1){
      ctx.font='9px "Courier New",monospace'; ctx.fillStyle='rgba(255,255,255,0.18)';
      let rt=`RUN ${runNum}`; ctx.fillText(rt,W/2-ctx.measureText(rt).width/2,62);
    }
  }
}

// ═══════════════════════════════════════════════════════════════
//  FIRE
// ═══════════════════════════════════════════════════════════════
class Fire {
  constructor(image, w, h) { this.w=w; this.h=h; this.image=new Image(); this.image.src=image; }
  draw(ctx, x, y) { ctx.beginPath(); ctx.drawImage(this.image,x-this.w/2,y-this.h/2); ctx.stroke(); }
}

// ═══════════════════════════════════════════════════════════════
//  LIGHTING
// ═══════════════════════════════════════════════════════════════
class Lighting {
  constructor() { this.flicker=0; this.flickerDir=1; this.flickerSpeed=0.08; }
  update(ms) {
    this.flicker+=this.flickerDir*this.flickerSpeed*(ms/25);
    if(this.flicker>1){this.flicker=1;this.flickerDir=-1;}
    if(this.flicker<0){this.flicker=0;this.flickerDir=1;}
    if(Math.random()<0.04) this.flickerDir*=-1;
  }
  draw(ctx, torchX, torchY) {
    let baseRadius=200+this.flicker*15;
    let grad=ctx.createRadialGradient(torchX,torchY,0,torchX,torchY,baseRadius);
    grad.addColorStop(0,'rgba(0,0,0,0)'); grad.addColorStop(0.4,'rgba(0,0,0,0.1)');
    grad.addColorStop(0.7,'rgba(0,0,0,0.5)'); grad.addColorStop(0.88,'rgba(0,0,0,0.78)');
    grad.addColorStop(1,'rgba(0,0,0,0.92)');
    ctx.fillStyle=grad; ctx.fillRect(0,0,640,400);
    ctx.fillStyle='rgba(0,0,0,0.92)';
    ctx.beginPath(); ctx.rect(0,0,640,400);
    ctx.arc(torchX,torchY,baseRadius,0,Math.PI*2,true); ctx.fill('evenodd');
    ctx.save(); ctx.globalCompositeOperation='lighter';
    let glow=ctx.createRadialGradient(torchX,torchY,0,torchX,torchY,80);
    let alpha=0.09+this.flicker*0.05;
    glow.addColorStop(0,`rgba(255,150,30,${alpha})`);
    glow.addColorStop(0.6,`rgba(255,80,10,${alpha*0.3})`);
    glow.addColorStop(1,'rgba(0,0,0,0)');
    ctx.fillStyle=glow; ctx.beginPath(); ctx.arc(torchX,torchY,80,0,Math.PI*2); ctx.fill();
    ctx.restore();
  }
}

// ═══════════════════════════════════════════════════════════════
//  PARTICLES
// ═══════════════════════════════════════════════════════════════
class Particles {
  constructor() { this.list=[]; }
  spawn(px, py, type, count=6) {
    for (let i=0; i<count; i++) {
      let angle=Math.random()*Math.PI*2;
      let speed=type==='wood'?1.5+Math.random()*2.5:2+Math.random()*3.5;
      this.list.push({
        x:px,y:py,vx:Math.cos(angle)*speed,vy:Math.sin(angle)*speed-(type==='wood'?2:3),
        life:1,decay:type==='wood'?0.025+Math.random()*0.02:0.04+Math.random()*0.03,
        size:type==='wood'?2+Math.random()*2:1.5,type,
        color:type==='wood'?`hsl(${28+Math.random()*20},60%,${30+Math.random()*20}%)`:
          type==='berry'?`hsl(${0+Math.random()*20},80%,${45+Math.random()*20}%)`:
          `hsl(${30+Math.random()*30},100%,${60+Math.random()*30}%)`,
      });
    }
  }
  update(ms) {
    let dt=ms/25; this.list=this.list.filter(p=>p.life>0);
    for (let p of this.list) { p.x+=p.vx*dt; p.y+=p.vy*dt; p.vy+=0.18*dt; p.life-=p.decay*dt; }
  }
  draw(ctx, backZone) {
    for (let p of this.list) {
      ctx.save(); ctx.globalAlpha=Math.max(0,p.life); ctx.fillStyle=p.color;
      if(p.type==='spark') ctx.globalCompositeOperation='lighter';
      ctx.fillRect(p.x-backZone-p.size/2,p.y-p.size/2,p.size,p.size); ctx.restore();
    }
  }
}

// ═══════════════════════════════════════════════════════════════
//  WEATHER
// ═══════════════════════════════════════════════════════════════
class Weather {
  constructor() {
    this.type='none'; this.drops=[]; this.fogAlpha=0; this.fogTarget=0;
    this.timer=0; this.interval=18000+Math.random()*12000; this._initDrops();
  }
  _initDrops() {
    this.drops=[];
    for(let i=0;i<120;i++) this.drops.push({x:Math.random()*640,y:Math.random()*400,len:8+Math.random()*10,speed:6+Math.random()*5,alpha:0.2+Math.random()*0.3});
  }
  update(ms) {
    this.timer+=ms;
    if(this.timer>=this.interval){
      this.timer=0; this.interval=18000+Math.random()*12000;
      let roll=Math.random();
      if(roll<0.35) this.type='rain';
      else if(roll<0.55) this.type='fog';
      else this.type='none';
      this.fogTarget=this.type==='fog'?0.18+Math.random()*0.12:0;
    }
    this.fogAlpha+=(this.fogTarget-this.fogAlpha)*0.02*(ms/25);
    if(this.type==='rain') {
      for(let d of this.drops){
        d.y+=d.speed*(ms/25); d.x-=0.5*(ms/25);
        if(d.y>400){d.y=-10;d.x=Math.random()*640;}
        if(d.x<0) d.x=640;
      }
    }
  }
  draw(ctx) {
    if(this.fogAlpha>0.005){ctx.fillStyle=`rgba(180,190,200,${this.fogAlpha})`;ctx.fillRect(0,48,640,352);}
    if(this.type==='rain'){
      ctx.save(); ctx.strokeStyle='rgba(180,210,255,0.35)'; ctx.lineWidth=0.8;
      for(let d of this.drops){ctx.globalAlpha=d.alpha;ctx.beginPath();ctx.moveTo(d.x,d.y);ctx.lineTo(d.x-2,d.y+d.len);ctx.stroke();}
      ctx.restore();
    }
  }
}

// ═══════════════════════════════════════════════════════════════
//  MINIMAP
// ═══════════════════════════════════════════════════════════════
class Minimap {
  constructor(mapLength) { this.worldWidth=mapLength*64; this.shops=[3200,6000]; }
  draw(ctx, playerWorldX, rivals, dwood) {
    let CW = ctx.canvas.width;
    let W=Math.floor(CW*0.31), H=10, X=Math.floor(CW*0.34), Y=Math.floor(ctx.canvas.height*0.965);
    ctx.fillStyle='rgba(0,0,0,0.6)'; ctx.fillRect(X-2,Y-2,W+4,H+4);
    ctx.fillStyle='rgba(255,255,255,0.04)'; ctx.fillRect(X,Y,W,H);
    let toMap=wx=>X+(wx/this.worldWidth)*W;
    for(let sx of this.shops){ctx.fillStyle='rgba(255,200,50,0.7)';ctx.fillRect(toMap(sx)-1,Y,2,H);}
    ctx.fillStyle='rgba(160,120,60,0.5)';
    for(let i=0;i<dwood.location.length;i++) if(dwood.location[i]!==0) ctx.fillRect(toMap(i*32),Y+3,1,H-6);
    if(rivals&&rivals.first){let node=rivals.first;while(node){if(!node.data.died){ctx.fillStyle='rgba(220,60,60,0.8)';ctx.fillRect(toMap(node.data.x)-1,Y+1,2,H-2);}node=node.next;}}
    ctx.fillStyle='rgba(255,255,255,0.95)'; ctx.fillRect(toMap(playerWorldX)-2,Y,3,H);
    ctx.strokeStyle='rgba(255,255,255,0.12)'; ctx.lineWidth=1; ctx.strokeRect(X,Y,W,H);
    ctx.font='8px "Courier New",monospace'; ctx.fillStyle='rgba(255,255,255,0.2)'; ctx.fillText('MAP',X-26,Y+8);
  }
}

// ═══════════════════════════════════════════════════════════════
//  FOOTPRINTS
// ═══════════════════════════════════════════════════════════════
class Footprints {
  constructor() { this.list=[]; this.stepTimer=0; }
  update(player, ms) {
    this.stepTimer+=ms;
    if(!player.stop&&this.stepTimer>280){
      this.stepTimer=0;
      this.list.push({x:player.x+player.backZone,y:player.y+2,alpha:0.45,dir:player.dir});
      if(this.list.length>30) this.list.shift();
    }
    for(let f of this.list) f.alpha-=0.003*(ms/25);
    this.list=this.list.filter(f=>f.alpha>0);
  }
  draw(ctx, backZone) {
    for(let f of this.list){
      ctx.save(); ctx.globalAlpha=f.alpha; ctx.fillStyle='#3a2a1a';
      let sx=f.x-backZone; ctx.fillRect(sx-3,f.y,3,2); ctx.fillRect(sx+1,f.y,3,2); ctx.restore();
    }
  }
}

// ═══════════════════════════════════════════════════════════════
//  WOOD INDICATOR
// ═══════════════════════════════════════════════════════════════
class WoodIndicator {
  constructor() { this.phase=0; }
  draw(ctx, player, dwood) {
    let wx=player.x+player.backZone;
    if(!dwood.isWood(wx)||player.collecting||player.jumping) return;
    this.phase+=0.12;
    let pulse=Math.sin(this.phase)*0.5+0.5;
    let area=Math.floor(wx/32);
    let drawX=area*32-player.backZone, drawY=dwood.location[area];
    let isBerry=dwood.types[area]===2;
    ctx.save();
    ctx.globalAlpha=0.3+pulse*0.4;
    ctx.strokeStyle=isBerry?'rgba(255,80,80,1)':'rgba(255,220,80,1)';
    ctx.lineWidth=1.5; ctx.strokeRect(drawX+1,drawY+1,28,22);
    ctx.font='bold 9px "Courier New",monospace';
    ctx.fillStyle=isBerry?`rgba(255,100,100,${0.5+pulse*0.5})`:`rgba(255,220,80,${0.5+pulse*0.5})`;
    ctx.fillText('[S]',drawX+8,drawY-3);
    ctx.restore();
  }
}

// ═══════════════════════════════════════════════════════════════
//  RECORDS
// ═══════════════════════════════════════════════════════════════
class Records {
  static load() { try{return JSON.parse(localStorage.getItem('dw_records')||'{}');}catch(e){return {};} }
  static save(rec) { try{localStorage.setItem('dw_records',JSON.stringify(rec));}catch(e){} }
  static update(score, timeMs) {
    let r=Records.load();
    r.bestScore=Math.max(r.bestScore||0,score);
    r.bestTime=Math.max(r.bestTime||0,timeMs);
    r.attempts=(r.attempts||0)+1;
    Records.save(r); return r;
  }
  static drawOnCanvas(ctx) {
    let r=Records.load(); if(!r.attempts) return;
    ctx.font='9px "Courier New",monospace'; ctx.fillStyle='#2a2a2a';
    let sec=Math.floor((r.bestTime||0)/1000),min=Math.floor(sec/60);
    let timeStr=min>0?`${min}m${sec%60}s`:`${sec}s`;
    let lines=[`best wood: ${r.bestScore||0}`,`best time: ${timeStr}`,`attempts:  ${r.attempts||0}`];
    lines.forEach((l,i)=>{ ctx.fillText(l,320-ctx.measureText(l).width/2,310+i*14); });
  }
}

// ═══════════════════════════════════════════════════════════════
//  AUDIO — синтетические звуки через Web Audio API
// ═══════════════════════════════════════════════════════════════
class Audio {
  constructor() {
    try {
      this.ctx = new (window.AudioContext||window.webkitAudioContext)();
      this.enabled = true;
    } catch(e) { this.enabled=false; }
  }
  _play(freq, type, duration, vol=0.15, freqEnd) {
    if(!this.enabled) return;
    try {
      let o=this.ctx.createOscillator();
      let g=this.ctx.createGain();
      o.connect(g); g.connect(this.ctx.destination);
      o.type=type; o.frequency.setValueAtTime(freq,this.ctx.currentTime);
      if(freqEnd) o.frequency.exponentialRampToValueAtTime(freqEnd,this.ctx.currentTime+duration);
      g.gain.setValueAtTime(vol,this.ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001,this.ctx.currentTime+duration);
      o.start(); o.stop(this.ctx.currentTime+duration);
    } catch(e){}
  }
  chop()   { this._play(180,'sawtooth',0.08,0.12,80); }   // рубка дерева
  jump()   { this._play(220,'sine',0.15,0.08,440); }       // прыжок
  shop()   { this._play(440,'sine',0.2,0.1,880); this._play(660,'sine',0.3,0.08,880); }  // магазин
  berry()  { this._play(520,'sine',0.12,0.1,780); }        // ягоды
  die()    { this._play(220,'sawtooth',0.4,0.15,55); }     // смерть
  step()   { this._play(60,'sine',0.04,0.04); }            // шаг (тихий)
  levelUp(){ this._play(330,'sine',0.1,0.12,660); setTimeout(()=>this._play(440,'sine',0.15,0.12,880),100); setTimeout(()=>this._play(660,'sine',0.2,0.15,990),220); }
}

// ═══════════════════════════════════════════════════════════════
//  UPGRADE SCREEN
// ═══════════════════════════════════════════════════════════════
class UpgradeScreen {
  constructor() {
    this.visible=false; this.cards=[]; this.hovered=-1; this.onPick=null;
    this.runScore=0; this.runTime=0; this.runNum=1;
    this.upgrades={startFood:0,speed:0,collectTime:0,inflateSlow:0,eatSlow:0};
  }
  static ALL_UPGRADES() {
    return [
      {id:'startFood',  icon:'🍖',name:'Запас еды',    desc:'+2 еды на старт',        color:'#7ecb7e'},
      {id:'speed',      icon:'👟',name:'Скорость',      desc:'Бег быстрее',            color:'#6ec6e8'},
      {id:'collectTime',icon:'🪓',name:'Острый топор',  desc:'Рубка быстрее',          color:'#c8a96e'},
      {id:'inflateSlow',icon:'📉',name:'Заморозка цен', desc:'Инфляция медленнее',     color:'#a0a0cc'},
      {id:'eatSlow',    icon:'🧘',name:'Аскет',         desc:'Голод наступает позже',  color:'#e8a06e'},
    ];
  }
  show(score, timeMs, runNum, callback) {
    this.visible=true; this.runScore=score; this.runTime=timeMs;
    this.runNum=runNum; this.onPick=callback; this.hovered=-1;
    let all=UpgradeScreen.ALL_UPGRADES();
    for(let i=all.length-1;i>0;i--){let j=Math.floor(Math.random()*(i+1));[all[i],all[j]]=[all[j],all[i]];}
    this.cards=all.slice(0,3);
  }
  hide() { this.visible=false; }
  onMouseMove(cx,cy) {
    if(!this.visible) return; this.hovered=-1;
    this.cards.forEach((c,i)=>{let r=this._cardRect(i);if(cx>=r.x&&cx<=r.x+r.w&&cy>=r.y&&cy<=r.y+r.h)this.hovered=i;});
  }
  onClick(cx,cy) {
    if(!this.visible) return false;
    for(let i=0;i<this.cards.length;i++){
      let r=this._cardRect(i);
      if(cx>=r.x&&cx<=r.x+r.w&&cy>=r.y&&cy<=r.y+r.h){
        this.upgrades[this.cards[i].id]++;
        this.hide(); if(this.onPick) this.onPick(this.cards[i]); return true;
      }
    }
    return false;
  }
  _cardRect(i){let cW=158,cH=120,gap=18,total=3*158+2*18,sX=(640-total)/2;return{x:sX+i*(cW+gap),y:218,w:cW,h:cH};}
  draw(ctx) {
    if(!this.visible) return;
    ctx.fillStyle='rgba(5,3,8,0.93)'; ctx.fillRect(0,0,640,400);
    ctx.fillStyle='rgba(255,255,255,0.015)';
    for(let y=0;y<400;y+=3) ctx.fillRect(0,y,640,1);

    // заголовок
    ctx.font='bold 11px "Courier New",monospace'; ctx.fillStyle='#444';
    let hdr=this.runNum>1?`RUN ${this.runNum} COMPLETE`:'RUN COMPLETE';
    ctx.fillText(hdr,320-ctx.measureText(hdr).width/2,38);

    // статистика
    let sec=Math.floor(this.runTime/1000),min=Math.floor(sec/60);
    let timeStr=min>0?`${min}m ${sec%60}s`:`${sec}s`;
    ctx.font='bold 28px "Courier New",monospace'; ctx.fillStyle='#ddd';
    let statStr=`wood: ${this.runScore}   time: ${timeStr}`;
    ctx.fillText(statStr,320-ctx.measureText(statStr).width/2,75);

    ctx.font='11px "Courier New",monospace'; ctx.fillStyle='#555';
    ctx.fillText('— choose an upgrade —',320-ctx.measureText('— choose an upgrade —').width/2,110);
    ctx.fillStyle='rgba(255,255,255,0.07)'; ctx.fillRect(80,122,480,1);

    // активные апгрейды
    let acquired=UpgradeScreen.ALL_UPGRADES().filter(u=>this.upgrades[u.id]>0);
    if(acquired.length>0){
      ctx.font='10px "Courier New",monospace'; ctx.fillStyle='#383838'; ctx.fillText('active:',80,145);
      acquired.forEach((u,i)=>{ctx.font='11px "Courier New",monospace';ctx.fillStyle=u.color;ctx.fillText(`${u.icon} ${u.name} ×${this.upgrades[u.id]}`,130+i*130,145);});
    }

    // карточки
    this.cards.forEach((card,i)=>{
      let r=this._cardRect(i),hov=this.hovered===i;
      if(hov){ctx.shadowColor=card.color;ctx.shadowBlur=18;}
      ctx.fillStyle=hov?'rgba(30,28,36,0.98)':'rgba(18,16,22,0.95)';
      this._roundRect(ctx,r.x,r.y,r.w,r.h,6); ctx.fill();
      ctx.strokeStyle=hov?card.color:'rgba(255,255,255,0.1)'; ctx.lineWidth=hov?1.5:1;
      this._roundRect(ctx,r.x,r.y,r.w,r.h,6); ctx.stroke(); ctx.shadowBlur=0;
      ctx.font='26px sans-serif'; ctx.fillText(card.icon,r.x+r.w/2-13,r.y+34);
      ctx.font=`bold 12px "Courier New",monospace`; ctx.fillStyle=hov?card.color:'#ccc';
      ctx.fillText(card.name,r.x+r.w/2-ctx.measureText(card.name).width/2,r.y+60);
      ctx.font='10px "Courier New",monospace'; ctx.fillStyle='#555';
      ctx.fillText(card.desc,r.x+r.w/2-ctx.measureText(card.desc).width/2,r.y+80);
      let lvl=this.upgrades[card.id];
      if(lvl>0){ctx.font='9px "Courier New",monospace';ctx.fillStyle=card.color;let lt=`LVL ${lvl} → ${lvl+1}`;ctx.fillText(lt,r.x+r.w/2-ctx.measureText(lt).width/2,r.y+108);}
      ctx.lineWidth=1;
    });
    ctx.font='9px "Courier New",monospace'; ctx.fillStyle='#2a2a2a';
    ctx.fillText('click a card to continue',320-ctx.measureText('click a card to continue').width/2,380);
  }
  _roundRect(ctx,x,y,w,h,r){
    ctx.beginPath();ctx.moveTo(x+r,y);ctx.lineTo(x+w-r,y);ctx.arcTo(x+w,y,x+w,y+r,r);
    ctx.lineTo(x+w,y+h-r);ctx.arcTo(x+w,y+h,x+w-r,y+h,r);ctx.lineTo(x+r,y+h);
    ctx.arcTo(x,y+h,x,y+h-r,r);ctx.lineTo(x,y+r);ctx.arcTo(x,y,x+r,y,r);ctx.closePath();
  }
}

// ═══════════════════════════════════════════════════════════════
//  DWFuncs
// ═══════════════════════════════════════════════════════════════
class DWFuncs {
  static collManager(player, dwood, particles, audio) {
    let position=Math.floor(player.x/32);
    let wx=player.x+player.backZone;
    if(dwood.isWood(wx)&&!player.jumping){
      let isBerry=dwood.isBerry(wx);
      player.collecting=true;
      let collectMs=isBerry?400:850;  // ягоды собираются быстрее
      let i=0, loading=setInterval(function(){i++;player.load=i;},50);
      if(audio) audio.chop();
      setTimeout(function(){
        if(dwood.isWood(player.x+player.backZone)&&position==Math.floor(player.x/32)&&!player.jumping){
          if(isBerry){
            // ягоды — прямо дают еду
            player.food+=2;
            if(particles) particles.spawn(player.x+player.backZone,player.y-20,'berry',6);
            if(audio) audio.berry();
          } else {
            player.woodCollection();
            if(particles) particles.spawn(player.x+player.backZone,player.y-20,'wood',8);
          }
          dwood.collection(player.x+player.backZone);
        }
        clearInterval(loading); player.load=0; player.collecting=false;
      }, collectMs);
    }
  }
  static movingManager(player, ground, dwood, ms, firstLaunch=false) {
    if(firstLaunch){
      addEventListener("keydown",function(e){
        if(player.stop){
          if(e.keyCode==68){player.dir=1;player.stop=false;}
          else if(e.keyCode==65){player.dir=-1;player.stop=false;}
        } else if(e.keyCode==16&&!player.jumping){
          player.jump();
          if(window._audio) window._audio.jump();
        }
        if(!player.collecting&&e.keyCode==83) DWFuncs.collManager(player,dwood,window._particles,window._audio);
        if(e.keyCode==27){if(window._pauseToggle)window._pauseToggle();}
      });
      addEventListener("keyup",function(e){if(e.keyCode==68||e.keyCode==65)player.stop=true;});
    }
    if(!player.stop) player.moving(ground.relief,ms);
  }
  static rivalForeach(node,ctx,backZonePlayer,relief,dwood,ms){
    function inside(node){
      if(node!=null){
        node.data.AI(node.data,relief,dwood,ms);
        node.data.gravity(relief,ms);
        node.data.draw(ctx,backZonePlayer);
        // удаляем только после 3сек анимации
        if(node.next!=null) inside(node.next);
      }
    }
    inside(node);
  }
  static collector(...list){
    for(let i=0;i<list.length;i++)
      list[i].removeAllByCond(b=>b.data.died==true&&b.data.diedTimer>3000);
  }
  static newRival(list,player,location,mapLength,runNum){
    let position=player.x+player.backZone+600;
    // с каждым забегом боты немного быстрее
    if(position<mapLength*64&&DWFuncs.checkRivalSpawn(location,Math.floor(position/32))){
      let speedBonus=Math.min((runNum-1)*0.15, 1.0);
      let rival=new Rival('../img/rival2.png',position,300,51,64);
      rival.step=2.3+speedBonus;
      list.add(rival);
    }
  }
  static checkRivalSpawn(location,chunk,visibility=7){
    let flag=false,from=Math.max(0,chunk-visibility),to=Math.min(location.length,chunk+visibility);
    for(from;from<to;from++){if(location[from]!=0){flag=true;break;}} return flag;
  }
  static diedWindow(ctx,ms){
    let W=ctx.canvas.width, H=ctx.canvas.height;
    ctx.fillStyle='rgba(10,0,0,0.92)'; ctx.fillRect(0,0,W,H);
    ctx.fillStyle='rgba(180,30,30,0.6)'; ctx.fillRect(0,0,W,3);
    let sec=Math.floor(ms/1000),min=Math.floor(sec/60);
    let timeStr=min>0?`${min} min ${sec%60} sec`:`${sec} sec`;
    ctx.font='bold 42px "Courier New",monospace'; ctx.fillStyle='#cc2222';
    let t1='YOU DIED'; ctx.fillText(t1,W/2-ctx.measureText(t1).width/2,H*0.44);
    ctx.fillStyle='rgba(180,30,30,0.3)'; ctx.fillRect(W/2-120,H*0.47,240,1);
    ctx.font='14px "Courier New",monospace'; ctx.fillStyle='#666';
    ctx.fillText('survived',W/2-ctx.measureText('survived').width/2,H*0.54);
    ctx.font='bold 22px "Courier New",monospace'; ctx.fillStyle='#aaa';
    ctx.fillText(timeStr,W/2-ctx.measureText(timeStr).width/2,H*0.61);
    ctx.font='11px "Courier New",monospace'; ctx.fillStyle='#444';
    ctx.fillText('press START to try again',W/2-ctx.measureText('press START to try again').width/2,H*0.73);
  }
}
/*jshint esversion: 6 */

let player        = new Player('../img/player2.png', 16, 300, 51, 64, 3.4);
    player.setVars(0);
let gameIsRunning = false;
let paused        = false;
let game, rivalCycle, collectorCycle, buyCycle, eatCycle;
let glbuy    = 18;
let lifetime;
let runNum   = 1;  // счётчик забегов

let upgradeScreen = new UpgradeScreen();
window._particles = null;
window._audio     = null;
window._pauseToggle = null;

function applyUpgrades(ups) { player.step = 3.4 + ups.speed * 0.3; }
function getInflateInterval(ups) { return 12000 + ups.inflateSlow * 2000; }
function getEatInterval(ups)     { return 11000 + ups.eatSlow * 1000; }

// ─── MAIN ────────────────────────────────────────────────────
function main() {
  gameIsRunning = true; paused = false;

  let screen    = document.getElementById('screen');
  let ctx       = screen.getContext('2d');
  let time      = new Date();
  let ms        = 20;
  let mapLength = 100;
  let buy       = glbuy;
  let ups       = upgradeScreen.upgrades;

  let wood       = new Background();
  let ground     = new Ground('../img/grass.jpg', mapLength);
  let dwood      = new Resources(ground.relief);
  let scores     = new Interface();
  let torch      = new Fire('../img/fireInTheDark.png', 1400, 875);
  let rivals     = new LinkedList();
  let shop       = new Shop('../img/shop.png', 6000);
  let mshop      = new Shop('../img/shop.png', 3200);
  let lighting   = new Lighting();
  let particles  = new Particles();
  let weather    = new Weather();
  let minimap    = new Minimap(mapLength);
  let footprints = new Footprints();
  let woodInd    = new WoodIndicator();
  let audio      = new Audio();

  window._particles = particles;
  window._audio     = audio;

  applyUpgrades(ups);
  player.food = 10 + ups.startFood * 2;

  // разблокируем AudioContext после первого взаимодействия
  document.addEventListener('keydown', function unlock() {
    if (audio.ctx && audio.ctx.state === 'suspended') audio.ctx.resume();
    document.removeEventListener('keydown', unlock);
  }, {once:true});

  window._pauseToggle = function() {
    if(!gameIsRunning||upgradeScreen.visible) return;
    paused=!paused; if(!paused) time=new Date();
  };

  screen.addEventListener('mousemove', function(e) {
    let rect=screen.getBoundingClientRect();
    upgradeScreen.onMouseMove((e.clientX-rect.left)*(640/rect.width),(e.clientY-rect.top)*(400/rect.height));
  });
  screen.addEventListener('click', function(e) {
    if(!upgradeScreen.visible) return;
    let rect=screen.getBoundingClientRect();
    upgradeScreen.onClick((e.clientX-rect.left)*(640/rect.width),(e.clientY-rect.top)*(400/rect.height));
  });

  if (ctx) { DWFuncs.movingManager(player,ground,dwood,ms,true); game=setInterval(render,25); }

  let stepSoundTimer = 0;

  function drawPause(ctx) {
    ctx.fillStyle='rgba(0,0,0,0.6)'; ctx.fillRect(0,0,640,400);
    ctx.font='bold 32px "Courier New",monospace'; ctx.fillStyle='#aaa';
    let t='PAUSED'; ctx.fillText(t,320-ctx.measureText(t).width/2,195);
    ctx.font='12px "Courier New",monospace'; ctx.fillStyle='#444';
    let s='ESC to resume'; ctx.fillText(s,320-ctx.measureText(s).width/2,225);
  }

  function render() {
    if(upgradeScreen.visible){ctx.clearRect(0,0,640,400);upgradeScreen.draw(ctx);return;}
    if(paused){drawPause(ctx);return;}

    ms=new Date()-time; time=new Date();

    DWFuncs.movingManager(player,ground,dwood,ms);
    player.gravity(ground.relief,ms);
    if(player.backZone>5760) stop();

    particles.update(ms);
    lighting.update(ms);
    weather.update(ms);
    footprints.update(player,ms);

    // звук шагов
    stepSoundTimer+=ms;
    if(!player.stop&&!player.jumping&&stepSoundTimer>320){
      stepSoundTimer=0; audio.step();
    }

    ctx.clearRect(0,0,640,400);
    wood.draw(ctx,player);
    weather.draw(ctx);
    ground.draw(ctx,player.backZone);
    let playerWX=player.x+player.backZone;
    shop.draw(ctx,player.backZone,playerWX,player.point,glbuy);
    mshop.draw(ctx,player.backZone,playerWX,player.point,glbuy);
    dwood.draw(ctx,player.backZone);
    footprints.draw(ctx,player.backZone);
    DWFuncs.rivalForeach(rivals.first,ctx,player.backZone,ground.relief,dwood,ms);
    woodInd.draw(ctx,player,dwood);
    player.draw(ctx);
    torch.draw(ctx,player.x+(player.dir==1?20:-20),player.y-40);
    if(weather.type==='rain') weather.draw(ctx);
    particles.draw(ctx,player.backZone);
    lighting.draw(ctx,player.x+(player.dir==1?20:-20),player.y-55);
    scores.draw(ctx,playerWX,player.food,player.point,buy,ms,runNum);
    minimap.draw(ctx,playerWX,rivals,dwood);

    if(player.food<=0){
      let lived=new Date()-lifetime;
      DWFuncs.diedWindow(ctx,lived);
      audio.die();
      for(var i=0;i<dwood.location.length;i++) dwood.location[i]=0;
      stop();
    }

    // магазин — звук при входе в зону
    if(playerWX>3200&&playerWX<3264){
      let gained=Math.floor(player.point/glbuy);
      if(gained>0) audio.shop();
      player.food+=gained;
      player.point=player.point%glbuy;
    }
  }

  collectorCycle = setInterval(DWFuncs.collector, 20000, rivals);
  rivalCycle     = setInterval(DWFuncs.newRival, Math.max(5000, 10000-runNum*500), rivals, player, dwood.location, mapLength, runNum);
  buyCycle       = setInterval(function(){let up=Math.floor(glbuy/10);glbuy+=up;buy+=up;}, getInflateInterval(ups));
  eatCycle       = setInterval(function(){player.food-=1;}, getEatInterval(ups));
}

// ─── стартовый экран ─────────────────────────────────────────
function drawStartScreen() {
  let screen=document.getElementById('screen');
  let ctx=screen.getContext('2d');
  ctx.fillStyle='#060606'; ctx.fillRect(0,0,640,400);
  let vignette=ctx.createRadialGradient(320,200,80,320,200,360);
  vignette.addColorStop(0,'rgba(0,0,0,0)'); vignette.addColorStop(1,'rgba(0,0,0,0.85)');
  ctx.fillStyle=vignette; ctx.fillRect(0,0,640,400);
  ctx.fillStyle='rgba(255,255,255,0.018)';
  for(let y=0;y<400;y+=4) ctx.fillRect(0,y,640,1);
  ctx.font='bold 58px "Courier New",monospace'; ctx.fillStyle='#ffffff'; ctx.globalAlpha=0.9;
  let title='DEADWOOD'; ctx.fillText(title,320-ctx.measureText(title).width/2,160);
  ctx.globalAlpha=1;
  ctx.font='12px "Courier New",monospace'; ctx.fillStyle='#555';
  let sub='a survival platformer'; ctx.fillText(sub,320-ctx.measureText(sub).width/2,182);
  ctx.fillStyle='rgba(255,255,255,0.08)'; ctx.fillRect(220,198,200,1);
  let hints=[['A / D','move'],['SHIFT','jump'],['S','collect / eat berries'],['ESC','pause']];
  ctx.font='11px "Courier New",monospace'; let hintY=222;
  hints.forEach(([key,action])=>{
    ctx.fillStyle='#777'; ctx.fillText(key,235,hintY);
    ctx.fillStyle='#3a3a3a'; ctx.fillText('—',288,hintY);
    ctx.fillStyle='#4a4a4a'; ctx.fillText(action,303,hintY);
    hintY+=16;
  });
  Records.drawOnCanvas(ctx);
  ctx.font='10px "Courier New",monospace'; ctx.fillStyle='#333';
  let ps='▼  press start  ▼'; ctx.fillText(ps,320-ctx.measureText(ps).width/2,360);
}
window.addEventListener('load', drawStartScreen);

// ─── отдельный цикл для экрана апгрейдов ─────────────────────
function _runUpgradeLoop() {
  let screen=document.getElementById('screen');
  let ctx=screen.getContext('2d');
  let loop=setInterval(function(){
    if(!upgradeScreen.visible){clearInterval(loop);return;}
    ctx.clearRect(0,0,640,400); upgradeScreen.draw(ctx);
  },25);
}

function start() { if(!gameIsRunning) restart(); }

function stop() {
  gameIsRunning=false; paused=false;
  clearInterval(game); clearInterval(rivalCycle);
  clearInterval(collectorCycle); clearInterval(buyCycle); clearInterval(eatCycle);

  let lived=new Date()-lifetime;
  let score=player.point;
  Records.update(score,lived);

  player.x=16; player.backZone=0;
  let nextRunNum=runNum+1;

  if(player.food>0){
    player.food+=Math.floor(player.point/glbuy);
    player.point=player.point%glbuy;
    if(window._audio) window._audio.levelUp();
    setTimeout(()=>{
      upgradeScreen.show(score,lived,nextRunNum,function(chosen){
        runNum=nextRunNum; glbuy=18;
        player.x=16; player.backZone=0;
        lifetime=new Date(); main();
      });
      _runUpgradeLoop();
    },800);
  } else {
    setTimeout(()=>{
      upgradeScreen.show(score,lived,nextRunNum,function(chosen){
        runNum=nextRunNum; glbuy=18;
        player.x=16; player.backZone=0;
        player.food=10; player.point=0;
        lifetime=new Date(); main();
      });
      _runUpgradeLoop();
    },1800);
  }
}

function restart() {
  player.x=16; player.backZone=0; player.food=10; player.point=0;
  glbuy=18; runNum=1;
  upgradeScreen.upgrades={startFood:0,speed:0,collectTime:0,inflateSlow:0,eatSlow:0};
  lifetime=new Date(); main();
}
